import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getCosmosIntelligence(walletAddress) {
  const chains = ["cosmos-mainnet", "osmosis-mainnet", "juno-mainnet"];
  const results = await Promise.all(
    chains.map(chain =>
      client.BalanceService.getTokenBalancesForWalletAddress(chain, walletAddress)
    )
  );
  return results.map((r, i) => ({ chain: chains[i], items: r.data?.items }));
}
